                const recommendationText = lines[1] || 'A Wonderful Experience';
                const reasonText = lines[2] || 'No reason, just feel it.';

                // --- 核心修改逻辑 ---
                let recommendationHTML = recommendationText;
                const separators = [' by ', '——', '—', ' - '];
